document.querySelectorAll(".cp").forEach(c=>{const t=c.querySelector(".cp__copy"),o=c.querySelector(".cp__pre");!t||!o||t.addEventListener("click",async()=>{const n=document.createElement("textarea");n.innerHTML=o.textContent??"";const r=n.value;try{await navigator.clipboard.writeText(r),t.classList.add("cp__copy--done");const e=t.querySelector(".cp__copy-text");e&&(e.textContent="Copied!"),setTimeout(()=>{t.classList.remove("cp__copy--done"),e&&(e.textContent="Copy")},1500)}catch{}})});
